export function isRowIndeterminate(id, s, getParents) {
    // Isolated row selection does not support indeterminate.
    if (s.kind === "isolated")
        return false;
    const parents = getParents(id);
    parents.push(id);
    const base = s.selected;
    let current = s.children.get(parents[0]);
    if (!current)
        return base;
    for (const p of parents.slice(1)) {
        const next = current?.children?.get(p);
        // We haven't finishing going down this path but have encountered the end.
        if (!next) {
            return false;
        }
        else {
            current = next;
        }
    }
    if (!current.children)
        return false;
    const stack = [...current.children.values()];
    while (stack.length) {
        const next = stack.pop();
        if (next.selected != null)
            return true;
        if (next.children)
            stack.push(...next.children.values());
    }
    return false;
}
